     5→// Method definitions below
     6→template <class T>
     7→CommBuffer<T>::CommBuffer(int tag, int send_rank, int recv_rank, mpi_comm_t comm,
     8→                          std::function<T()> get_resource, bool do_sparse_allocation)
     9→    : state_(std::make_shared<BufferState>(BufferState::stale)),
    10→      comm_type_(std::make_shared<BuffCommType>(BuffCommType::both)),
    11→      started_irecv_(std::make_shared<bool>(false)),
    12→      nrecv_tries_(std::make_shared<int>(0)),
    13→#ifdef MPI_PARALLEL
    14→      my_request_(std::make_shared<MPI_Request>(MPI_REQUEST_NULL)),
    15→#endif
    16→      tag_(tag), send_rank_(send_rank), recv_rank_(recv_rank), comm_(comm),
    17→      get_resource_(get_resource), buf_() {
    18→  my_rank = Globals::my_rank;
    19→  if (send_rank == recv_rank) {
    20→    assert(my_rank == send_rank);
    21→    *comm_type_ = BuffCommType::both;
    22→  } else if (my_rank == send_rank) {
    23→    *comm_type_ = BuffCommType::sender;
    24→  } else if (my_rank == recv_rank) {
    25→    *comm_type_ = BuffCommType::receiver;
    26→    if (do_sparse_allocation) *comm_type_ = BuffCommType::sparse_receiver;
    27→  } else {
    28→    // This is an error
    29→    std::cout << "CommBuffer initialization error" << std::endl;
    30→  }
    31→}
