    36→    : buf_(in.buf_), state_(in.state_), comm_type_(in.comm_type_),
    37→      started_irecv_(in.started_irecv_), nrecv_tries_(in.nrecv_tries_),
    38→      my_request_(in.my_request_), tag_(in.tag_), send_rank_(in.send_rank_),
    39→      recv_rank_(in.recv_rank_), comm_(in.comm_), active_(in.active_) {
