    94→template <class T>
    95→void CommBuffer<T>::Send() noexcept {
    96→  if (!active_) {
    97→    SendNull();
    98→    return;
    99→  }
   100→
   101→  PARTHENON_DEBUG_REQUIRE(*state_ == BufferState::stale,
   102→                          "Trying to send from buffer that hasn't been staled.");
   103→  *state_ = BufferState::sending;
   104→  if (*comm_type_ == BuffCommType::sender) {
   105→// Make sure that this request isn't still out,
   106→// this could be blocking
   107→#ifdef MPI_PARALLEL
   108→    tau::LogMsgSend(this, buf_.size(), recv_rank_, tag_, (uint64_t)tau::GetUsSince(0));
   109→    PARTHENON_REQUIRE(
   110→        buf_.size() > 0,
   111→        "Trying to send zero size buffer, which will be interpreted as sending_null.");
   112→    PARTHENON_MPI_CHECK(MPI_Wait(my_request_.get(), MPI_STATUS_IGNORE));
   113→
   114→    // SendGap();
   115→
   116→    PARTHENON_MPI_CHECK(MPI_Isend(buf_.data(), buf_.size(),
   117→                                  MPITypeMap<buf_base_t>::type(), recv_rank_, tag_, comm_,
   118→                                  my_request_.get()));
   119→#endif
   120→  }
   121→  if (*comm_type_ == BuffCommType::receiver) {
   122→    // This is an error
   123→    PARTHENON_FAIL("Trying to send from a receiver");
   124→  }
   125→}
