   127→template <class T>
   128→void CommBuffer<T>::SendNull() noexcept {
   129→  PARTHENON_DEBUG_REQUIRE(*state_ == BufferState::stale,
   130→                          "Trying to send_null from buffer that hasn't been staled.");
   131→  *state_ = BufferState::sending_null;
   132→  if (*comm_type_ == BuffCommType::sender) {
   133→// Make sure that this request isn't still out,
   134→// this could be blocking
   135→#ifdef MPI_PARALLEL
   136→    PARTHENON_MPI_CHECK(MPI_Wait(my_request_.get(), MPI_STATUS_IGNORE));
   137→    PARTHENON_MPI_CHECK(MPI_Isend(&null_buf_, 0, MPITypeMap<buf_base_t>::type(),
   138→                                  recv_rank_, tag_, comm_, my_request_.get()));
   139→#endif
   140→  }
   141→  if (*comm_type_ == BuffCommType::receiver) {
   142→    // This is an error
   143→    PARTHENON_FAIL("Trying to send from a receiver");
   144→  }
