   147→template <class T>
   148→void CommBuffer<T>::DrainPendingSends(SendDrainQueue &dq) {
   149→  // Give up ownership only of MPI_Request structs if sends are pending.
   150→  // We don't give up ownership of the buffers, as we assume that this will
   151→  // only be called after the receiver has received the actual data.
   152→
   153→  if (*comm_type_ != BuffCommType::sender) {
   154→    return;
   155→  }
   156→
   157→  if (*state_ != BufferState::sending && *state_ != BufferState::sending_null) {
   158→    return;
   159→  }
   160→
   161→  int flag;
   162→  PARTHENON_MPI_CHECK(MPI_Test(my_request_.get(), &flag, MPI_STATUS_IGNORE));
   163→  if (!flag) {
   164→    dq.AddSendRequest(std::move(my_request_));
   165→    my_request_ = std::make_shared<MPI_Request>(MPI_REQUEST_NULL);
   166→  }
   167→
   168→  *state_ = BufferState::stale;
   169→
   170→  return;
   171→}
