   173→template <class T>
   174→bool CommBuffer<T>::IsSendPending() {
   175→  if (*comm_type_ != BuffCommType::sender) {
   176→    return false;
   177→  }
   178→
   179→  if (*state_ != BufferState::sending && *state_ != BufferState::sending_null) {
   180→    return false;
   181→  }
   182→
   183→  int flag;
   184→  PARTHENON_MPI_CHECK(MPI_Test(my_request_.get(), &flag, MPI_STATUS_IGNORE));
   185→  return !flag;
   186→}
