   188→template <class T>
   189→std::shared_ptr<MPI_Request> CommBuffer<T>::ReleaseMPIReq() {
   190→  if (*comm_type_ != BuffCommType::sender) {
   191→    std::stringstream msg;
   192→    msg << "Trying to release MPI request from a non-sender buffer. "
   193→        << "CommType: " << CommBufferLogging::BufCommType2Str(*comm_type_);
   194→    std::cout << msg.str() << std::endl;
   195→  }
   196→
   197→  if (*state_ != BufferState::sending && *state_ != BufferState::sending_null) {
   198→    std::stringstream msg;
   199→    msg << "Trying to release MPI request from a buffer that is not in the sending "
   200→           "state. "
   201→        << "State: " << CommBufferLogging::BufState2Str(*state_);
   202→    std::cout << msg.str() << std::endl;
   203→  }
   204→
   205→  auto req = my_request_;
   206→  my_request_ = std::make_shared<MPI_Request>(MPI_REQUEST_NULL);
   207→  *state_ = BufferState::stale;
   208→
   209→  return req;
